import React, { useState, useRef } from "react";
import { useFormik } from "formik";
import * as Yup from "yup";
import "../css/login.css";
import { FaUser, FaEnvelope, FaMobileAlt, FaArrowRight, FaCheckCircle, FaRedo } from "react-icons/fa";

/* ─── STEP 1 VALIDATION ─── */
const detailsSchema = Yup.object({
  username: Yup.string()
    .min(3, "At least 3 characters")
    .max(30, "Max 30 characters")
    .required("Username is required"),
  email: Yup.string()
    .email("Enter a valid email address")
    .required("Email is required"),
  mobile: Yup.string()
    .matches(/^[6-9]\d{9}$/, "Enter a valid 10-digit mobile number")
    .required("Mobile number is required"),
});

/* ─── OTP VALIDATION ─── */
const otpSchema = Yup.object({
  otp: Yup.string()
    .matches(/^\d{6}$/, "OTP must be exactly 6 digits")
    .required("OTP is required"),
});

export default function Login() {
  const [step, setStep]         = useState(1); // 1 = details, 2 = otp, 3 = success
  const [countdown, setCountdown] = useState(0);
  const timerRef = useRef(null);

  /* ── start resend countdown ── */
  const startCountdown = () => {
    setCountdown(30);
    timerRef.current = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) { clearInterval(timerRef.current); return 0; }
        return prev - 1;
      });
    }, 1000);
  };

  /* ─── STEP 1 FORMIK ─── */
  const detailsFormik = useFormik({
    initialValues: { username: "", email: "", mobile: "" },
    validationSchema: detailsSchema,
    onSubmit: () => {
      // simulate sending OTP
      setStep(2);
      startCountdown();
    },
  });

  /* ─── STEP 2 FORMIK ─── */
  const otpFormik = useFormik({
    initialValues: { otp: "" },
    validationSchema: otpSchema,
    onSubmit: (values) => {
      // Accept "123456" as mock correct OTP
      if (values.otp === "123456") {
        setStep(3);
      } else {
        otpFormik.setFieldError("otp", "Incorrect OTP. Try 123456");
      }
    },
  });

  const handleResend = () => {
    otpFormik.resetForm();
    startCountdown();
  };

  return (
    <div className="lp-root">

      {/* LEFT PANEL */}
      <div className="lp-left">
        <div className="lp-left-blob lp-blob-1" />
        <div className="lp-left-blob lp-blob-2" />
        <div className="lp-left-content">
          <a href="/" className="lp-back-logo">RentSpace</a>
          <div className="lp-left-text">
            <p className="lp-left-tag">Welcome back</p>
            <h2 className="lp-left-h2">Your next home is one login away.</h2>
            <p className="lp-left-sub">
              Access verified listings across Coimbatore — houses, apartments, PGs, hostels &amp; offices.
            </p>
          </div>
          <div className="lp-trust-badges">
            <div className="lp-badge"><FaCheckCircle /> No Brokerage</div>
            <div className="lp-badge"><FaCheckCircle /> Verified Listings</div>
            <div className="lp-badge"><FaCheckCircle /> Instant Booking</div>
          </div>
        </div>
      </div>

      {/* RIGHT PANEL */}
      <div className="lp-right">
        <div className="lp-card">

          {/* STEP INDICATOR */}
          <div className="lp-steps">
            {["Details", "OTP", "Done"].map((s, i) => (
              <React.Fragment key={s}>
                <div className={`lp-step ${step > i ? "done" : ""} ${step === i + 1 ? "active" : ""}`}>
                  <div className="lp-step-dot">
                    {step > i + 1 ? <FaCheckCircle /> : i + 1}
                  </div>
                  <span>{s}</span>
                </div>
                {i < 2 && <div className={`lp-step-line ${step > i + 1 ? "done" : ""}`} />}
              </React.Fragment>
            ))}
          </div>

          {/* ── STEP 1: DETAILS ── */}
          {step === 1 && (
            <form className="lp-form" onSubmit={detailsFormik.handleSubmit} noValidate>
              <div className="lp-form-header">
                <h2>Create / Login</h2>
                <p>Enter your details to receive an OTP</p>
              </div>

              {/* USERNAME */}
              <div className={`lp-field ${detailsFormik.touched.username && detailsFormik.errors.username ? "error" : ""} ${detailsFormik.touched.username && !detailsFormik.errors.username ? "valid" : ""}`}>
                <label htmlFor="username">Username</label>
                <div className="lp-input-wrap">
                  <FaUser className="lp-icon" />
                  <input
                    id="username"
                    name="username"
                    type="text"
                    placeholder="Enter Your Name"
                    value={detailsFormik.values.username}
                    onChange={detailsFormik.handleChange}
                    onBlur={detailsFormik.handleBlur}
                  />
                  {detailsFormik.touched.username && !detailsFormik.errors.username && (
                    <FaCheckCircle className="lp-valid-icon" />
                  )}
                </div>
                {detailsFormik.touched.username && detailsFormik.errors.username && (
                  <p className="lp-error">{detailsFormik.errors.username}</p>
                )}
              </div>

              {/* EMAIL */}
              <div className={`lp-field ${detailsFormik.touched.email && detailsFormik.errors.email ? "error" : ""} ${detailsFormik.touched.email && !detailsFormik.errors.email ? "valid" : ""}`}>
                <label htmlFor="email">Email Address</label>
                <div className="lp-input-wrap">
                  <FaEnvelope className="lp-icon" />
                  <input
                    id="email"
                    name="email"
                    type="email"
                    placeholder="Email"
                    value={detailsFormik.values.email}
                    onChange={detailsFormik.handleChange}
                    onBlur={detailsFormik.handleBlur}
                  />
                  {detailsFormik.touched.email && !detailsFormik.errors.email && (
                    <FaCheckCircle className="lp-valid-icon" />
                  )}
                </div>
                {detailsFormik.touched.email && detailsFormik.errors.email && (
                  <p className="lp-error">{detailsFormik.errors.email}</p>
                )}
              </div>

              {/* MOBILE */}
              <div className={`lp-field ${detailsFormik.touched.mobile && detailsFormik.errors.mobile ? "error" : ""} ${detailsFormik.touched.mobile && !detailsFormik.errors.mobile ? "valid" : ""}`}>
                <label htmlFor="mobile">Mobile Number</label>
                <div className="lp-input-wrap">
                  <span className="lp-prefix">+91</span>
                  <FaMobileAlt className="lp-icon lp-icon-after-prefix" />
                  <input
                    id="mobile"
                    name="mobile"
                    type="tel"
                    placeholder=""
                    maxLength={10}
                    value={detailsFormik.values.mobile}
                    onChange={detailsFormik.handleChange}
                    onBlur={detailsFormik.handleBlur}
                  />
                  {detailsFormik.touched.mobile && !detailsFormik.errors.mobile && (
                    <FaCheckCircle className="lp-valid-icon" />
                  )}
                </div>
                {detailsFormik.touched.mobile && detailsFormik.errors.mobile && (
                  <p className="lp-error">{detailsFormik.errors.mobile}</p>
                )}
              </div>

              <button type="submit" className="lp-btn">
                Send OTP <FaArrowRight />
              </button>

              <p className="lp-terms">
                By continuing, you agree to RentSpace's <a href="#">Terms</a> &amp; <a href="#">Privacy Policy</a>.
              </p>
            </form>
          )}

          {/* ── STEP 2: OTP ── */}
          {step === 2 && (
            <form className="lp-form" onSubmit={otpFormik.handleSubmit} noValidate>
              <div className="lp-form-header">
                <h2>Verify OTP</h2>
                <p>
                  Sent to <strong>+91 {detailsFormik.values.mobile}</strong> &amp;{" "}
                  <strong>{detailsFormik.values.email}</strong>
                </p>
              </div>

              <div className={`lp-field lp-otp-field ${otpFormik.touched.otp && otpFormik.errors.otp ? "error" : ""} ${otpFormik.touched.otp && !otpFormik.errors.otp ? "valid" : ""}`}>
                <label htmlFor="otp">Enter 6-digit OTP</label>
                <div className="lp-input-wrap">
                  <input
                    id="otp"
                    name="otp"
                    type="text"
                    inputMode="numeric"
                    maxLength={6}
                    placeholder="• • • • • •"
                    className="lp-otp-input"
                    value={otpFormik.values.otp}
                    onChange={otpFormik.handleChange}
                    onBlur={otpFormik.handleBlur}
                  />
                </div>
                {otpFormik.touched.otp && otpFormik.errors.otp && (
                  <p className="lp-error">{otpFormik.errors.otp}</p>
                )}
                <p className="lp-hint">Hint: use <strong>123456</strong> for demo</p>
              </div>

              <button type="submit" className="lp-btn">
                Verify &amp; Login <FaArrowRight />
              </button>

              <div className="lp-resend">
                {countdown > 0 ? (
                  <p>Resend OTP in <strong>{countdown}s</strong></p>
                ) : (
                  <button type="button" className="lp-resend-btn" onClick={handleResend}>
                    <FaRedo /> Resend OTP
                  </button>
                )}
              </div>

              <button
                type="button"
                className="lp-back-btn"
                onClick={() => { setStep(1); otpFormik.resetForm(); }}
              >
                ← Change Details
              </button>
            </form>
          )}

          {/* ── STEP 3: SUCCESS ── */}
          {step === 3 && (
            <div className="lp-success">
              <div className="lp-success-icon">
                <FaCheckCircle />
              </div>
              <h2>You're in!</h2>
              <p>Welcome, <strong>{detailsFormik.values.username}</strong>. Your account is verified.</p>
              <a href="/" className="lp-btn lp-btn-link">
                Explore Rentals <FaArrowRight />
              </a>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}
